// Pattern recogniser for the magic handoff CSR convention. The same predicate
// runs in two places: the QEMU TCG plugin (C) and the vsim PC pre-scan (C++).

#ifndef HYBRID_INSN_MATCH_H
#define HYBRID_INSN_MATCH_H

#include <stdbool.h>
#include <stdint.h>

#ifdef __cplusplus
extern "C" {
#endif

typedef enum
{
  HYBRID_HANDOFF_NONE    = 0,
  HYBRID_HANDOFF_ENTER   = 1,  // csrwi 0x7C0, 0
  HYBRID_HANDOFF_EXIT    = 2,  // csrwi 0x7C0, 1
  HYBRID_HANDOFF_RUNTIME = 3,  // csrw  0x7C0, rs1 (kind read at run time)
} hybrid_handoff_kind;

#define HYBRID_TRIGGER_CSR 0x7C0u

// Returns true when `insn` is a SYSTEM-opcode write with rd=0 to CSR 0x7C0.
// On match, *out_kind is set to ENTER, EXIT, or RUNTIME.
static inline bool hybrid_match_handoff_insn(uint32_t insn,
                                             hybrid_handoff_kind* out_kind)
{
  if ((insn & 0x7Fu) != 0x73u) return false;          // SYSTEM opcode
  if (((insn >> 7) & 0x1Fu) != 0u) return false;      // rd = x0
  if (((insn >> 20) & 0xFFFu) != HYBRID_TRIGGER_CSR) return false;

  const uint32_t funct3 = (insn >> 12) & 0x7u;
  if (funct3 == 0b001u) {
    *out_kind = HYBRID_HANDOFF_RUNTIME;
    return true;
  }
  if (funct3 == 0b101u) {
    const uint32_t uimm = (insn >> 15) & 0x1Fu;
    if (uimm == 0u) {
      *out_kind = HYBRID_HANDOFF_ENTER;
      return true;
    }
    if (uimm == 1u) {
      *out_kind = HYBRID_HANDOFF_EXIT;
      return true;
    }
    return false;
  }
  return false;
}

#ifdef __cplusplus
}  // extern "C"
#endif

#endif  // HYBRID_INSN_MATCH_H
